     1→import {
     2→  BadRequestException,
     3→  Injectable,
     4→  NotFoundException,
     5→} from '@nestjs/common';
     6→import { InjectRepository } from '@nestjs/typeorm';
     7→import { Repository } from 'typeorm';
     8→import { DockerService } from '../docker/docker.service';
     9→import { AsteriskService } from '../asterisk/asterisk.service';
    10→import { Provider, ProviderType } from '../providers/provider.entity';
    11→import { CreateAgentDto } from './dto/create-agent.dto';
    12→import { RunAgentDto } from './dto/run-agent.dto';
    13→import { UpdateAgentDto } from './dto/update-agent.dto';
    14→import { Agent, AgentMode, AgentStatus } from './agent.entity';
    15→import {
    16→  buildPaginatedResult,
    17→  getPagination,
    18→  PaginatedResult,
    19→  PaginationQuery,
    20→} from '../common/pagination';
    21→
    22→@Injectable()
    23→export class AgentsService {
    24→  private readonly defaultImage =
    25→    process.env.CORE_DEFAULT_IMAGE || 'agentvoiceresponse/avr-core:latest';
    26→
    27→  constructor(
    28→    @InjectRepository(Agent)
    29→    private readonly agentRepository: Repository<Agent>,
    30→    @InjectRepository(Provider)
    31→    private readonly providerRepository: Repository<Provider>,
    32→    private readonly dockerService: DockerService,
    33→    private readonly asteriskService: AsteriskService,
    34→  ) {}
    35→
    36→  async create(createAgentDto: CreateAgentDto): Promise<Agent> {
    37→    const agent = this.agentRepository.create({
    38→      name: createAgentDto.name,
    39→      mode: createAgentDto.mode ?? AgentMode.PIPELINE,
    40→      port: Math.floor(Math.random() * 1000) + 5000,
    41→    });
    42→
    43→    agent.providerAsr = await this.resolveProvider(
    44→      createAgentDto.providerAsrId,
    45→    );
    46→    agent.providerLlm = await this.resolveProvider(
    47→      createAgentDto.providerLlmId,
    48→    );
    49→    agent.providerTts = await this.resolveProvider(
    50→      createAgentDto.providerTtsId,
    51→    );
    52→    agent.providerSts = await this.resolveProvider(
    53→      createAgentDto.providerStsId,
    54→    );
    55→
    56→    this.assertModeRequirements(agent);
    57→
    58→    const saved = await this.agentRepository.save(agent);
    59→    return saved;
    60→  }
    61→
    62→  async findAll(query: PaginationQuery): Promise<PaginatedResult<Agent>> {
    63→    const { skip, take, page, limit } = getPagination(query);
    64→
    65→    const [data, total] = await this.agentRepository.findAndCount({
    66→      skip,
    67→      take,
    68→    });
    69→
    70→    return buildPaginatedResult(data, total, page, limit);
    71→  }
    72→
    73→  async findOne(id: string): Promise<Agent> {
    74→    const agent = await this.agentRepository.findOne({ where: { id } });
    75→    if (!agent) {
    76→      throw new NotFoundException('Agent not found');
    77→    }
    78→    return agent;
    79→  }
    80→
    81→  async update(id: string, updateAgentDto: UpdateAgentDto): Promise<Agent> {
    82→    const agent = await this.findOne(id);
    83→
    84→    if (updateAgentDto.name) {
    85→      agent.name = updateAgentDto.name;
    86→    }
    87→
    88→    if (updateAgentDto.mode) {
    89→      agent.mode = updateAgentDto.mode;
    90→    }
    91→
    92→    if (updateAgentDto.providerAsrId !== undefined) {
    93→      agent.providerAsr = await this.resolveProvider(
    94→        updateAgentDto.providerAsrId,
    95→      );
    96→    }
    97→    if (updateAgentDto.providerLlmId !== undefined) {
    98→      agent.providerLlm = await this.resolveProvider(
    99→        updateAgentDto.providerLlmId,
   100→      );
   101→    }
   102→    if (updateAgentDto.providerTtsId !== undefined) {
   103→      agent.providerTts = await this.resolveProvider(
   104→        updateAgentDto.providerTtsId,
   105→      );
   106→    }
   107→    if (updateAgentDto.providerStsId !== undefined) {
   108→      agent.providerSts = await this.resolveProvider(
   109→        updateAgentDto.providerStsId,
   110→      );
   111→    }
   112→
   113→    this.assertModeRequirements(agent);
   114→
   115→    const saved = await this.agentRepository.save(agent);
   116→    return saved;
   117→  }
   118→
   119→  async remove(id: string): Promise<void> {
   120→    const result = await this.agentRepository.delete({ id });
   121→    if (!result.affected) {
   122→      throw new NotFoundException('Agent not found');
   123→    }
   124→    // TODO: remove phone related to agent from asterisk
   125→  }
   126→
   127→  async runAgent(id: string, runAgentDto: RunAgentDto) {
   128→    const agent = await this.findOne(id);
   129→    const env = this.buildEnv(agent, runAgentDto.env ?? []);
   130→    const coreEnv = this.buildEnv(agent, [
   131→      `WEBHOOK_URL=${process.env.WEBHOOK_URL}`,
   132→      `WEBHOOK_SECRET=${process.env.WEBHOOK_SECRET}`,
   133→    ]);
   134→
   135→    const containerIds: Record<string, string> = {};
   136→
   137→    const mappedProviders: Array<[ProviderType, Provider | null]> =
   138→      agent.mode === AgentMode.STS
   139→        ? [[ProviderType.STS, agent.providerSts ?? null]]
   140→        : [
   141→            [ProviderType.ASR, agent.providerAsr ?? null],
   142→            [ProviderType.LLM, agent.providerLlm ?? null],
   143→            [ProviderType.TTS, agent.providerTts ?? null],
   144→          ];
   145→
   146→    for (const [type, provider] of mappedProviders) {
   147→      if (!provider) {
   148→        continue;
   149→      }
   150→      const containerName = this.buildContainerName(
   151→        agent.id,
   152→        type.toLowerCase(),
   153→      );
   154→      // Generate a random port between 6000 and 6999 for each provider container
   155→      const port = Math.floor(Math.random() * 1000) + 6000;
   156→      const image = this.extractImage(provider);
   157→      const providerEnv = this.extendEnv(env, provider, type, port);
   158→      if (type == ProviderType.STS) {
   159→        coreEnv.push(`STS_URL=ws://${containerName}:${port}`);
   160→      } else {
   161→        coreEnv.push(
   162→          `${type.toLowerCase()}_URL=http://${containerName}:${port}`,
   163→        );
   164→      }
   165→      containerIds[type] = await this.dockerService.runContainer(
   166→        containerName,
   167→        image,
   168→        providerEnv,
   169→      );
   170→    }
   171→
   172→    if (Object.keys(containerIds).length) {
   173→      const containerName = this.buildContainerName(agent.id);
   174→      coreEnv.push(`PORT=${agent.port}`);
   175→      containerIds['core'] = await this.dockerService.runContainer(
   176→        containerName,
   177→        this.defaultImage,
   178→        coreEnv,
   179→      );
   180→    }
   181→
   182→    agent.status = AgentStatus.RUNNING;
   183→    return this.agentRepository.save(agent);
   184→  }
   185→
   186→  async stopAgent(id: string): Promise<Agent> {
   187→    const agent = await this.findOne(id);
   188→    const names = this.getContainerNames(agent.id, agent.mode);
   189→    for (const name of names) {
   190→      await this.dockerService.stopContainer(name);
   191→    }
   192→
   193→    agent.status = AgentStatus.STOPPED;
   194→    return this.agentRepository.save(agent);
   195→  }
   196→
   197→  private async resolveProvider(id?: string | null): Promise<Provider | null> {
   198→    if (!id) {
   199→      return null;
   200→    }
   201→
   202→    const provider = await this.providerRepository.findOne({ where: { id } });
   203→    if (!provider) {
   204→      throw new NotFoundException(`Provider ${id} not found`);
   205→    }
   206→    return provider;
   207→  }
