app.post('/text-to-speech-stream', async (req, res) => {
  try {
    const { text } = req.body;

    if (!text) {
      return res.status(400).json({ error: 'Text is required' });
    }

    console.log(`[Edge TTS] Generating audio for: "${text.substring(0, 50)}..."`);

    // Create temporary file for audio output
    const tempFile = path.join('/tmp', `tts_${Date.now()}.wav`);

    // Build edge-tts command
    const args = [
      '--text', text,
      '--voice', VOICE,
      '--rate', RATE,
      '--pitch', PITCH,
      '--write-media', tempFile
    ];

    const edgeTTS = spawn('edge-tts', args);

    let errorOutput = '';

    edgeTTS.stderr.on('data', (data) => {
      errorOutput += data.toString();
    });

    edgeTTS.on('close', (code) => {
      if (code !== 0) {
        console.error('[Edge TTS] Error:', errorOutput);
        res.status(500).json({
          error: 'TTS generation failed',
          details: errorOutput
        });
        return;
      }

      // Stream the audio file back
      res.setHeader('Content-Type', 'audio/wav');

      const audioStream = fs.createReadStream(tempFile);

      audioStream.pipe(res);

      audioStream.on('end', () => {
        // Clean up temp file
        fs.unlink(tempFile, (err) => {
          if (err) console.error('[Edge TTS] Failed to delete temp file:', err);
        });
      });

      audioStream.on('error', (err) => {
        console.error('[Edge TTS] Stream error:', err);
        res.status(500).json({ error: 'Audio streaming failed' });
      });
    });

  } catch (error) {
    console.error('[Edge TTS] Error:', error.message);
    res.status(500).json({
      error: error.message,
      provider: 'edge-tts'
    });
  }
});

