   300→        <Skeleton key={idx} className="h-10 w-full" />
   301→      ))}
   302→    </div>
   303→  );
   304→}
   305→
   306→function DetailSkeleton() {
   307→  return (
   308→    <div className="space-y-2">
   309→      {Array.from({ length: 6 }).map((_, idx) => (
   310→        <Skeleton key={idx} className="h-5 w-full" />
   311→      ))}
   312→    </div>
   313→  );
   314→}
   315→
   316→interface EventRowProps {
   317→  event: CallEventDto;
   318→  dictionary: ReturnType<typeof useI18n>['dictionary'];
   319→}
   320→
   321→function EventRow({ event, dictionary }: EventRowProps) {
   322→  const timestamp = useMemo(() => {
   323→    const date = new Date(event.timestamp);
   324→    return Number.isNaN(date.getTime())
   325→      ? event.timestamp
   326→      : `${date.toLocaleDateString()} ${date.toLocaleTimeString()}`;
   327→  }, [event.timestamp]);
   328→
   329→  const renderPayload = () => {
   330→    if (!event.payload) {
   331→      return null;
   332→    }
   333→    if (event.type === 'transcription') {
   334→      const roleRaw = String(event.payload.role ?? 'user');
   335→      const text = String(event.payload.text ?? '');
   336→      const roleLabel =
   337→        roleRaw === 'agent'
   338→          ? dictionary.calls.transcript.agent
   339→          : roleRaw === 'user'
   340→            ? dictionary.calls.transcript.user
   341→            : roleRaw;
   342→      return (
   343→        <div className="space-y-1">
   344→          <div className="text-xs uppercase text-muted-foreground">{roleLabel}</div>
   345→          <p className="rounded bg-background/60 p-3 text-sm">{text}</p>
   346→        </div>
   347→      );
   348→    }
   349→    if (event.type === 'dtmf_digit') {
   350→      return (
   351→        <div className="text-sm text-muted-foreground">
   352→          Digit:{' '}
   353→          <span className="font-mono">{String(event.payload.digit ?? '')}</span>
   354→        </div>
   355→      );
   356→    }
   357→    if (Object.keys(event.payload).length === 0) {
   358→      return null;
   359→    }
   360→    return (
   361→      <pre className="whitespace-pre-wrap rounded bg-background/60 p-2 text-xs text-muted-foreground">
   362→        {JSON.stringify(event.payload, null, 2)}
   363→      </pre>
   364→    );
   365→  };
   366→
   367→  const label = dictionary.calls.events[event.type];
   368→
   369→  return (
   370→    <div className="rounded-md border border-border/40 bg-card/40 p-3 text-sm">
   371→      <div className="flex flex-wrap items-center justify-between gap-2">
   372→        <span className="font-medium text-foreground">{label}</span>
   373→        <span className="font-mono text-xs text-muted-foreground">{timestamp}</span>
   374→      </div>
   375→      {renderPayload()}
   376→    </div>
   377→  );
   378→}
